files.initialValue:
variable "environment" {
  type = string
}

variable "service_name" {
  type = string
}

variable "kms_key_id" {
  type     = string
  nullable = true

  validation {
    condition     = var.environment != "prod" || var.kms_key_id != null
    error_message = "Production log buckets require a customer-managed KMS key."
  }
}
